import numpy as np
from sklearn.model_selection import train_test_split
from tensorflow.keras.preprocessing.image import load_img
from tensorflow.keras.applications.vgg16 import VGG16
from tensorflow.keras.applications.resnet50 import ResNet50
from tensorflow.keras.applications.inception_v3 import InceptionV3
from tensorflow.keras.models import Model, Sequential
from tensorflow.keras.layers import Dense, Dropout, Flatten, GlobalAveragePooling2D, Activation
import os
import requests

# Define the data structure for storing image labels
class ImageLabel:
    def __init__(self, path, label):
        self.path = path
        self.label = label

# Load the images and their corresponding labels from the dataset
def load_data(data_dir):
    # Get a list of all files in the data directory
    file_list = os.listdir(data_dir)
    
    # Initialize an empty list to store the image labels
    labels = []
    
    # Loop through each file and extract its label
    for file in file_list:
        # Get the path of the current file
        file_path = os.path.join(data_dir, file)
        
        # Extract the label from the file name
        label = int(file.split("_")[0])
        
        # Create a new ImageLabel object and add it to the list
        labels.append(ImageLabel(file_path, label))
    
    # Return the list of image labels
    return labels

# Aggregate the labels using majority voting
def aggregate_labels(labels):
    # Initialize a dictionary to store the counts of each label
    label_counts = {}
    
    # Loop through each label and increment its count in the dictionary
    for label in labels:
        if label.label not in label_counts:
            label_counts[label.label] = 1
        else:
            label_counts[label.label] += 1
    
    # Return the most frequent label
    return max(label_counts, key=label_counts.get)

# Train a model on the labeled data without validation
def train_model(data_dir):
    # Load the image labels from the dataset
    labels = load_data(data_dir)
    
    # Aggregate the labels using majority voting
    label = aggregate_labels(labels)
    
    # Initialize a new model and set its parameters
    model = Sequential()
    model.add(GlobalAveragePooling2D())
    model.add(Flatten())
    model.add(Dense(128, activation='relu'))
    model.add(Dropout(0.5))
    model.add(Dense(64, activation='relu'))
    model.add(Dropout(0.5))
    model.add(Dense(label.num_classes, activation='softmax'))
    
    # Compile the model with a loss function and an optimizer
    model.compile(loss='categorical_crossentropy', optimizer='adam', metrics=['accuracy'])
    
    # Split the data into training and testing sets
    x_train, x_test, y_train, y_test = train_test_split(data_dir, labels, test_size=0.2, random_state=42)
    
    # Train the model on the training data
    model.fit(x_train, y_train, epochs=10, batch_size=32, validation_data=(x_test, y_test))
    
    # Return the trained model
    return model

# Define a function to predict labels for new images
def predict_labels(model, data_dir):
    # Load the image labels from the dataset
    labels = load_data(data_dir)
    
    # Aggregate the labels using majority voting
    label = aggregate_labels(labels)
    
    # Initialize a list to store the predicted labels
    preds = []
    
    # Loop through each image in the dataset and predict its label
    for file in os.listdir(data_dir):
        # Get the path of the current file
        file_path = os.path.join(data_dir, file)
        
        # Load the image using Keras' load_img function
        img = load_img(file_path)
        
        # Convert the image to a numpy array
        x = np.array(img)
        
        # Reshape the numpy array to fit the model input shape
        x = x.reshape((1, 224, 224, 3))
        
        # Use the model to predict the label of the current image
        pred = model.predict(x)
        
        # Add the predicted label to the list
        preds.append(np.argmax(pred))
    
    # Return the list of predicted labels
    return preds

# Define a function to evaluate the performance of the model on a test set
def evaluate_model(model, data_dir):
    # Load the image labels from the dataset
    labels = load_data(data_dir)
    
    # Aggregate the labels using majority voting
    label = aggregate_labels(labels)
    
    # Split the data into training and testing sets
    x_train, x_test, y_train, y_test = train_test_split(data_dir, labels, test_size=0.2, random_state=42)
    
    # Use the model to predict the labels of the testing data
    preds = model.predict(x_test)
    
    # Calculate the accuracy and confusion matrix of the predictions
    acc = np.average(preds == y_test, axis=0)
    conf_mat = np.confusion_matrix(y_test, preds)
    
    # Return the accuracy and confusion matrix
    return acc, conf_mat

# Define a function to save the trained model to disk
def save_model(model, filepath):
    # Save the trained model to disk using Keras' model.save function
    model.save(filepath)